-- Table 1: field_of_study_aliases
CREATE TABLE IF NOT EXISTS field_of_study_aliases (
  id INT AUTO_INCREMENT PRIMARY KEY,
  canonical_field VARCHAR(255) NOT NULL,
  alias VARCHAR(255) NOT NULL,
  normalized VARCHAR(255) NOT NULL,
  INDEX idx_normalized (normalized),
  INDEX idx_canonical (canonical_field),
  UNIQUE KEY uq_field_alias (canonical_field, alias, normalized)
);

-- Table 2: degree_aliases
CREATE TABLE IF NOT EXISTS degree_aliases (
  id INT AUTO_INCREMENT PRIMARY KEY,
  degree_canonical VARCHAR(255) NOT NULL,
  alias VARCHAR(255) NOT NULL,
  normalized VARCHAR(255) NOT NULL,
  degree_level VARCHAR(100) NULL,
  country_scope VARCHAR(32) NOT NULL,
  INDEX idx_degree_alias_normalized (normalized),
  INDEX idx_degree_alias_canonical (degree_canonical),
  INDEX idx_degree_alias_scope (country_scope),
  UNIQUE KEY uq_degree_alias (degree_canonical, alias, country_scope)
);

-- Table 3: degree_field_map
CREATE TABLE IF NOT EXISTS degree_field_map (
  id INT AUTO_INCREMENT PRIMARY KEY,
  degree_canonical VARCHAR(255) NOT NULL,
  field_canonical VARCHAR(255) NOT NULL,
  INDEX idx_degree (degree_canonical),
  INDEX idx_field (field_canonical),
  UNIQUE KEY uq_degree_field (degree_canonical, field_canonical)
);



























